         // POST: Departments/Edit/5
         [HttpPost]
         [ValidateAntiForgeryToken]
         public ActionResult Edit([Bind("DepartmentID", "Name", "Budget", "StartDate", "InstructorID", "RowVersion")] Department department)
         {
             try
             {
                 if (ModelState.IsValid)
                 {
