using ContosoUniversity.Data;
using ContosoUniversity.Models;
using ContosoUniversity.Services;
using Microsoft.AspNetCore.Http;
using Microsoft.AspNetCore.Mvc;
using Microsoft.AspNetCore.Mvc.ViewFeatures;
using Microsoft.EntityFrameworkCore;
using Moq;
using System;
using System.Collections.Generic;

namespace ContosoUniversity.Tests.Helpers
{
    public static class TestHelpers
    {
        public static SchoolContext CreateContext(string dbName = null)
        {
            dbName ??= Guid.NewGuid().ToString();
            var options = new DbContextOptionsBuilder<SchoolContext>()
                .UseInMemoryDatabase(databaseName: dbName)
                .Options;
            return new SchoolContext(options);
        }

        public static void SetupController(Controller controller)
        {
            var httpContext = new DefaultHttpContext();
            controller.ControllerContext = new ControllerContext
            {
                HttpContext = httpContext
            };
            controller.TempData = new TempDataDictionary(httpContext, Mock.Of<ITempDataProvider>());
        }

        /// <summary>
        /// Seeds a comprehensive dataset suitable for most controller tests.
        /// Returns a context with: 2 instructors, 2 departments, 3 courses,
        /// 3 students, 3 enrollments, 1 office assignment, 2 course assignments.
        /// </summary>
        public static SchoolContext CreateSeededContext(string dbName = null)
        {
            var context = CreateContext(dbName);
            SeedTestData(context);
            return context;
        }

        public static void SeedTestData(SchoolContext context)
        {
            var instructor1 = new Instructor
            {
                LastName = "Doe",
                FirstMidName = "Jane",
                HireDate = new DateTime(2015, 1, 1),
                CourseAssignments = new List<CourseAssignment>()
            };
            var instructor2 = new Instructor
            {
                LastName = "Smith",
                FirstMidName = "John",
                HireDate = new DateTime(2010, 6, 15),
                CourseAssignments = new List<CourseAssignment>()
            };
            context.Instructors.AddRange(instructor1, instructor2);
            context.SaveChanges();

            // Office assignment for instructor1
            context.OfficeAssignments.Add(new OfficeAssignment
            {
                InstructorID = instructor1.ID,
                Location = "Room 101"
            });
            context.SaveChanges();

            var dept1 = new Department
            {
                Name = "Engineering",
                Budget = 350000m,
                StartDate = new DateTime(2007, 9, 1),
                InstructorID = instructor1.ID
            };
            var dept2 = new Department
            {
                Name = "Mathematics",
                Budget = 100000m,
                StartDate = new DateTime(2007, 9, 1),
                InstructorID = instructor2.ID
            };
            context.Departments.AddRange(dept1, dept2);
            context.SaveChanges();

            var course1 = new Course
            {
                CourseID = 1001,
                Title = "Chemistry",
                Credits = 3,
                DepartmentID = dept1.DepartmentID
            };
            var course2 = new Course
            {
                CourseID = 1002,
                Title = "Physics",
                Credits = 4,
                DepartmentID = dept1.DepartmentID
            };
            var course3 = new Course
            {
                CourseID = 1003,
                Title = "Calculus",
                Credits = 4,
                DepartmentID = dept2.DepartmentID
            };
            context.Courses.AddRange(course1, course2, course3);
            context.SaveChanges();

            // Course assignments
            context.CourseAssignments.AddRange(
                new CourseAssignment { InstructorID = instructor1.ID, CourseID = 1001 },
                new CourseAssignment { InstructorID = instructor2.ID, CourseID = 1003 }
            );
            context.SaveChanges();

            var student1 = new Student
            {
                LastName = "Alexander",
                FirstMidName = "Carson",
                EnrollmentDate = new DateTime(2020, 9, 1)
            };
            var student2 = new Student
            {
                LastName = "Brooks",
                FirstMidName = "Diana",
                EnrollmentDate = new DateTime(2021, 9, 1)
            };
            var student3 = new Student
            {
                LastName = "Clark",
                FirstMidName = "Edward",
                EnrollmentDate = new DateTime(2020, 9, 1)
            };
            context.Students.AddRange(student1, student2, student3);
            context.SaveChanges();

            context.Enrollments.AddRange(
                new Enrollment { StudentID = student1.ID, CourseID = 1001, Grade = Grade.A },
                new Enrollment { StudentID = student1.ID, CourseID = 1002, Grade = Grade.B },
                new Enrollment { StudentID = student2.ID, CourseID = 1001, Grade = Grade.C }
            );
            context.SaveChanges();
        }

        /// <summary>
        /// Drains the static notification queue to prevent cross-test interference.
        /// </summary>
        public static void DrainNotificationQueue()
        {
            var service = new NotificationService();
            while (service.ReceiveNotification() != null) { }
        }
    }
}

