            Assert.Null(instructor.CourseAssignments);
        }

        [Fact]
        public void Instructor_OfficeAssignment_InitiallyNull()
        {
            var instructor = new Instructor();
            Assert.Null(instructor.OfficeAssignment);
        }
    }
}

