{"file_text": "using System.Collections.Generic;
using System.Linq;
using Xunit;

namespace ContosoUniversity.Tests
{
    public class PaginatedListTests
    {
        [Fact]
        public void Constructor_SetsPageIndex()
        {
            var items = new List<string> { "a", "b" };
            var list = new PaginatedList<string>(items, 10, 2, 5);

            Assert.Equal(2, list.PageIndex);
        }

        [Fact]
        public void Constructor_CalculatesTotalPages()
        {
            var items = new List<string> { "a" };
            var list = new PaginatedList<string>(items, 10, 1, 3);

            Assert.Equal(4, list.TotalPages); // ceil(10/3) = 4
        }

        [Fact]
        public void Constructor_TotalPages_ExactDivision()
        {
            var items = new List<string> { "a" };
            var list = new PaginatedList<string>(items, 10, 1, 5);

            Assert.Equal(2, list.TotalPages);
        }

        [Fact]
        public void Constructor_AddsItemsToList()
        {
            var items = new List<int> { 1, 2, 3 };
            var list = new PaginatedList<int>(items, 10, 1, 5);

            Assert.Equal(3, list.Count);
            Assert.Contains(1, list);
            Assert.Contains(2, list);
            Assert.Contains(3, list);
        }

        [Fact]
        public void HasPreviousPage_False_OnFirstPage()
        {
            var list = new PaginatedList<int>(new List<int>(), 10, 1, 5);
            Assert.False(list.HasPreviousPage);
        }

        [Fact]
        public void HasPreviousPage_True_OnSecondPage()
        {
            var list = new PaginatedList<int>(new List<int>(), 10, 2, 5);
            Assert.True(list.HasPreviousPage);
        }

        [Fact]
        public void HasNextPage_True_WhenNotOnLastPage()
        {
            var list = new PaginatedList<int>(new List<int>(), 10, 1, 5);
            Assert.True(list.HasNextPage); // page 1 of 2
        }

        [Fact]
        public void HasNextPage_False_OnLastPage()
        {
            var list = new PaginatedList<int>(new List<int>(), 10, 2, 5);
            Assert.False(list.HasNextPage); // page 2 of 2
        }

        [Fact]
        public void HasNextPage_False_SinglePage()
        {
            var list = new PaginatedList<int>(new List<int>(), 3, 1, 5);
            Assert.False(list.HasNextPage); // page 1 of 1
        }

        [Fact]
        public void HasPreviousPage_False_SinglePage()
        {
            var list = new PaginatedList<int>(new List<int>(), 3, 1, 5);
            Assert.False(list.HasPreviousPage);
        }

        [Fact]
        public void Create_ReturnsCorrectPage()
        {
            var source = Enumerable.Range(1, 20).AsQueryable();
            var result = PaginatedList<int>.Create(source, 2, 5);

            Assert.Equal(2, result.PageIndex);
            Assert.Equal(4, result.TotalPages);
            Assert.Equal(5, result.Count);
            Assert.Equal(new[] { 6, 7, 8, 9, 10 }, result.ToList());
        }

        [Fact]
        public void Create_FirstPage()
        {
            var source = Enumerable.Range(1, 15).AsQueryable();
            var result = PaginatedList<int>.Create(source, 1, 5);

            Assert.Equal(1, result.PageIndex);
            Assert.Equal(3, result.TotalPages);
            Assert.Equal(new[] { 1, 2, 3, 4, 5 }, result.ToList());
        }

        [Fact]
        public void Create_LastPage_PartialItems()
        {
            var source = Enumerable.Range(1, 7).AsQueryable();
            var result = PaginatedList<int>.Create(source, 2, 5);

            Assert.Equal(2, result.PageIndex);
            Assert.Equal(2, result.TotalPages);
            Assert.Equal(new[] { 6, 7 }, result.ToList());
        }

        [Fact]
        public void Create_EmptySource()
        {
            var source = Enumerable.Empty<int>().AsQueryable();
            var result = PaginatedList<int>.Create(source, 1, 5);

            Assert.Equal(1, result.PageIndex);
            Assert.Equal(0, result.TotalPages);
            Assert.Empty(result);
        }

        [Fact]
        public void Create_SingleItem()
        {
            var source = new[] { 42 }.AsQueryable();
            var result = PaginatedList<int>.Create(source, 1, 10);

            Assert.Single(result);
            Assert.Equal(42, result[0]);
            Assert.False(result.HasPreviousPage);
            Assert.False(result.HasNextPage);
        }
    }
}
