using System;
using Xunit;

namespace ContosoUniversity.Tests.Services
{
    public class NotificationServiceTests : IDisposable
    {
        private readonly NotificationService _service;

        public NotificationServiceTests()
        {
            _service = new NotificationService();
            // Drain the static queue to ensure test isolation
            while (_service.ReceiveNotification() != null) { }
        }

        public void Dispose()
        {
            // Drain again after tests
            while (_service.ReceiveNotification() != null) { }
            _service.Dispose();
        }

        [Fact]
        public void SendNotification_EnqueuesNotification()
        {
            _service.SendNotification("Student", "1", EntityOperation.CREATE, "admin");

            var notification = _service.ReceiveNotification();
            Assert.NotNull(notification);
            Assert.Equal("Student", notification.EntityType);
            Assert.Equal("1", notification.EntityId);
            Assert.Equal("CREATE", notification.Operation);
            Assert.Equal("admin", notification.CreatedBy);
            Assert.False(notification.IsRead);
        }

        [Fact]
        public void SendNotification_WithDisplayName_GeneratesCorrectMessage()
        {
            _service.SendNotification("Course", "101", "Chemistry", EntityOperation.CREATE, "admin");

            var notification = _service.ReceiveNotification();
            Assert.NotNull(notification);
            Assert.Equal("New Course 'Chemistry' has been created", notification.Message);
        }

        [Fact]
        public void SendNotification_WithoutDisplayName_GeneratesIdBasedMessage()
        {
            _service.SendNotification("Course", "101", EntityOperation.CREATE, "admin");

            var notification = _service.ReceiveNotification();
            Assert.NotNull(notification);
            Assert.Equal("New Course (ID: 101) has been created", notification.Message);
        }

        [Fact]
        public void SendNotification_Update_GeneratesCorrectMessage()
        {
            _service.SendNotification("Student", "5", "John Doe", EntityOperation.UPDATE, "admin");

            var notification = _service.ReceiveNotification();
            Assert.Equal("Student 'John Doe' has been updated", notification.Message);
        }

        [Fact]
        public void SendNotification_Delete_GeneratesCorrectMessage()
        {
            _service.SendNotification("Department", "3", "Engineering", EntityOperation.DELETE, "admin");

            var notification = _service.ReceiveNotification();
            Assert.Equal("Department 'Engineering' has been deleted", notification.Message);
        }

        [Fact]
        public void SendNotification_DefaultUser_IsSystem()
        {
            _service.SendNotification("Student", "1", EntityOperation.CREATE);

            var notification = _service.ReceiveNotification();
            Assert.Equal("System", notification.CreatedBy);
        }

        [Fact]
        public void SendNotification_SetsCreatedAt()
        {
            var before = DateTime.Now;
            _service.SendNotification("Student", "1", EntityOperation.CREATE);
            var after = DateTime.Now;

            var notification = _service.ReceiveNotification();
            Assert.InRange(notification.CreatedAt, before, after);
        }

        [Fact]
        public void ReceiveNotification_ReturnsNull_WhenQueueEmpty()
        {
            var result = _service.ReceiveNotification();
            Assert.Null(result);
        }

        [Fact]
        public void ReceiveNotification_ReturnsFIFO()
        {
            _service.SendNotification("A", "1", EntityOperation.CREATE);
            _service.SendNotification("B", "2", EntityOperation.UPDATE);
            _service.SendNotification("C", "3", EntityOperation.DELETE);

            var first = _service.ReceiveNotification();
            var second = _service.ReceiveNotification();
            var third = _service.ReceiveNotification();

            Assert.Equal("A", first.EntityType);
            Assert.Equal("B", second.EntityType);
            Assert.Equal("C", third.EntityType);
        }

        [Fact]
        public void MarkAsRead_DoesNotThrow()
        {
            // MarkAsRead is a no-op for in-memory implementation
            var exception = Record.Exception(() => _service.MarkAsRead(42));
            Assert.Null(exception);
        }

        [Fact]
        public void Dispose_DoesNotThrow()
        {
            var service = new NotificationService();
            var exception = Record.Exception(() => service.Dispose());
            Assert.Null(exception);
        }

        [Fact]
        public void SendNotification_OverloadWithoutDisplayName_CallsMainOverload()
        {
            _service.SendNotification("Instructor", "7", EntityOperation.UPDATE, "teacher");

            var notification = _service.ReceiveNotification();
            Assert.NotNull(notification);
            Assert.Equal("Instructor", notification.EntityType);
            Assert.Equal("7", notification.EntityId);
            Assert.Equal("UPDATE", notification.Operation);
        }

        [Fact]
        public void SendNotification_WithEmptyDisplayName_UsesIdBased()
        {
            _service.SendNotification("Student", "1", "", EntityOperation.CREATE, "admin");

            var notification = _service.ReceiveNotification();
            Assert.Equal("New Student (ID: 1) has been created", notification.Message);
        }

        [Fact]
        public void SendNotification_WithWhitespaceDisplayName_UsesIdBased()
        {
            _service.SendNotification("Student", "1", "   ", EntityOperation.CREATE, "admin");

            var notification = _service.ReceiveNotification();
            Assert.Equal("New Student (ID: 1) has been created", notification.Message);
        }
    }
}

