using ContosoUniversity.Data;
using ContosoUniversity.Models;
using ContosoUniversity.Tests.Helpers;
using System.Linq;
using Xunit;

namespace ContosoUniversity.Tests.Data
{
    public class DbInitializerTests
    {
        [Fact]
        public void Initialize_SeedsStudents()
        {
            var context = TestHelpers.CreateContext();

            DbInitializer.Initialize(context);

            Assert.Equal(8, context.Students.Count());
        }

        [Fact]
        public void Initialize_SeedsInstructors()
        {
            var context = TestHelpers.CreateContext();

            DbInitializer.Initialize(context);

            Assert.Equal(5, context.Instructors.Count());
        }

        [Fact]
        public void Initialize_SeedsDepartments()
        {
            var context = TestHelpers.CreateContext();

            DbInitializer.Initialize(context);

            Assert.Equal(4, context.Departments.Count());
            Assert.Contains(context.Departments, d => d.Name == "English");
            Assert.Contains(context.Departments, d => d.Name == "Mathematics");
            Assert.Contains(context.Departments, d => d.Name == "Engineering");
            Assert.Contains(context.Departments, d => d.Name == "Economics");
        }

        [Fact]
        public void Initialize_SeedsCourses()
        {
            var context = TestHelpers.CreateContext();

            DbInitializer.Initialize(context);

            Assert.Equal(7, context.Courses.Count());
            Assert.Contains(context.Courses, c => c.Title == "Chemistry");
            Assert.Contains(context.Courses, c => c.Title == "Calculus");
        }

        [Fact]
        public void Initialize_SeedsEnrollments()
        {
            var context = TestHelpers.CreateContext();

            DbInitializer.Initialize(context);

            Assert.Equal(11, context.Enrollments.Count());
        }

        [Fact]
        public void Initialize_SeedsOfficeAssignments()
        {
            var context = TestHelpers.CreateContext();

            DbInitializer.Initialize(context);

            Assert.Equal(3, context.OfficeAssignments.Count());
        }

        [Fact]
        public void Initialize_SeedsCourseAssignments()
        {
            var context = TestHelpers.CreateContext();

            DbInitializer.Initialize(context);

            Assert.Equal(8, context.CourseAssignments.Count());
        }

        [Fact]
        public void Initialize_DoesNotReseeed_WhenStudentsExist()
        {
            var context = TestHelpers.CreateContext();
            // Pre-add a student
            context.Students.Add(new Student
            {
                LastName = "Test",
                FirstMidName = "User",
                EnrollmentDate = System.DateTime.Now
            });
            context.SaveChanges();

            DbInitializer.Initialize(context);

            // Should still only have the 1 student we added
            Assert.Equal(1, context.Students.Count());
        }

        [Fact]
        public void Initialize_EnrollmentsHaveGrades()
        {
            var context = TestHelpers.CreateContext();

            DbInitializer.Initialize(context);

            // Most enrollments have grades
            var withGrades = context.Enrollments.Count(e => e.Grade != null);
            Assert.True(withGrades > 0);

            // At least one enrollment without a grade
            var withoutGrades = context.Enrollments.Count(e => e.Grade == null);
            Assert.True(withoutGrades > 0);
        }

        [Fact]
        public void Initialize_DepartmentsHaveAdministrators()
        {
            var context = TestHelpers.CreateContext();

            DbInitializer.Initialize(context);

            foreach (var dept in context.Departments)
            {
                Assert.NotNull(dept.InstructorID);
            }
        }
    }
}

