using ContosoUniversity.Controllers;
using ContosoUniversity.Data;
using ContosoUniversity.Models;
using ContosoUniversity.Tests.Helpers;
using Microsoft.AspNetCore.Mvc;
using Microsoft.EntityFrameworkCore;
using System;
using System.Linq;
using Xunit;

namespace ContosoUniversity.Tests.Controllers
{
    public class StudentsControllerTests : IDisposable
    {
        private readonly SchoolContext _context;
        private readonly StudentsController _controller;

        public StudentsControllerTests()
        {
            TestHelpers.DrainNotificationQueue();
            _context = TestHelpers.CreateSeededContext();
            _controller = new StudentsController(_context);
            TestHelpers.SetupController(_controller);
        }

        public void Dispose()
        {
            TestHelpers.DrainNotificationQueue();
            _controller.Dispose();
            _context.Dispose();
        }

        // --- Index Tests ---

        [Fact]
        public void Index_ReturnsViewResult()
        {
            var result = _controller.Index(null, null, null, null);
            Assert.IsType<ViewResult>(result);
        }

        [Fact]
        public void Index_DefaultSort_OrdersByLastNameAscending()
        {
            var result = _controller.Index(null, null, null, null);

            var viewResult = Assert.IsType<ViewResult>(result);
            var model = Assert.IsAssignableFrom<PaginatedList<Student>>(viewResult.Model);
            Assert.True(model.Count >= 2);
            // Default sort is by LastName ascending
            var names = model.Select(s => s.LastName).ToList();
            Assert.Equal(names.OrderBy(n => n).ToList(), names);
        }

        [Fact]
        public void Index_NameDescSort_OrdersByLastNameDescending()
        {
            var result = _controller.Index("name_desc", null, null, null);

            var viewResult = Assert.IsType<ViewResult>(result);
            var model = Assert.IsAssignableFrom<PaginatedList<Student>>(viewResult.Model);
            var names = model.Select(s => s.LastName).ToList();
            Assert.Equal(names.OrderByDescending(n => n).ToList(), names);
        }

        [Fact]
        public void Index_DateSort_OrdersByEnrollmentDateAscending()
        {
            var result = _controller.Index("Date", null, null, null);

            var viewResult = Assert.IsType<ViewResult>(result);
            var model = Assert.IsAssignableFrom<PaginatedList<Student>>(viewResult.Model);
            var dates = model.Select(s => s.EnrollmentDate).ToList();
            Assert.Equal(dates.OrderBy(d => d).ToList(), dates);
        }

        [Fact]
        public void Index_DateDescSort_OrdersByEnrollmentDateDescending()
        {
            var result = _controller.Index("date_desc", null, null, null);

            var viewResult = Assert.IsType<ViewResult>(result);
            var model = Assert.IsAssignableFrom<PaginatedList<Student>>(viewResult.Model);
            var dates = model.Select(s => s.EnrollmentDate).ToList();
            Assert.Equal(dates.OrderByDescending(d => d).ToList(), dates);
        }

        [Fact]
        public void Index_SearchString_FiltersStudents()
        {
            var result = _controller.Index(null, null, "Alexander", null);

            var viewResult = Assert.IsType<ViewResult>(result);
            var model = Assert.IsAssignableFrom<PaginatedList<Student>>(viewResult.Model);
            Assert.Single(model);
            Assert.Equal("Alexander", model[0].LastName);
        }

        [Fact]
        public void Index_SearchByFirstName_FiltersStudents()
        {
            var result = _controller.Index(null, null, "Carson", null);

            var viewResult = Assert.IsType<ViewResult>(result);
            var model = Assert.IsAssignableFrom<PaginatedList<Student>>(viewResult.Model);
            Assert.Single(model);
            Assert.Equal("Carson", model[0].FirstMidName);
        }

        [Fact]
        public void Index_SearchString_SetsPageTo1()
        {
            var result = _controller.Index(null, null, "Alexander", 5);

            var viewResult = Assert.IsType<ViewResult>(result);
            var model = Assert.IsAssignableFrom<PaginatedList<Student>>(viewResult.Model);
            Assert.Equal(1, model.PageIndex);
        }

        [Fact]
        public void Index_NoSearchString_UsesCurrentFilter()
        {
            var result = _controller.Index(null, "Alexander", null, null);

            var viewResult = Assert.IsType<ViewResult>(result);
            var model = Assert.IsAssignableFrom<PaginatedList<Student>>(viewResult.Model);
            Assert.Single(model);
        }

        [Fact]
        public void Index_SetsViewBagProperties()
        {
            _controller.Index("Date", null, "test", null);

            Assert.Equal("Date", _controller.ViewBag.CurrentSort);
            Assert.Equal("date_desc", _controller.ViewBag.DateSortParm);
            Assert.Equal("", _controller.ViewBag.NameSortParm);
            Assert.Equal("test", _controller.ViewBag.CurrentFilter);
        }

        [Fact]
        public void Index_DefaultSortParms()
        {
            _controller.Index(null, null, null, null);

            Assert.Equal("name_desc", _controller.ViewBag.NameSortParm);
            Assert.Equal("Date", _controller.ViewBag.DateSortParm);
        }

        [Fact]
        public void Index_Pagination_DefaultPageSize10()
        {
            // Add more students to exceed page size
            for (int i = 0; i < 15; i++)
            {
                _context.Students.Add(new Student
                {
                    LastName = $"Test{i:D2}",
                    FirstMidName = "Student",
                    EnrollmentDate = new DateTime(2023, 1, 1)
                });
            }
            _context.SaveChanges();

            var result = _controller.Index(null, null, null, 1);

            var viewResult = Assert.IsType<ViewResult>(result);
            var model = Assert.IsAssignableFrom<PaginatedList<Student>>(viewResult.Model);
            Assert.Equal(10, model.Count);
            Assert.True(model.HasNextPage);
        }

        // --- Details Tests ---

        [Fact]
        public void Details_NullId_ReturnsBadRequest()
        {
            var result = _controller.Details(null);

            var statusResult = Assert.IsType<StatusCodeResult>(result);
            Assert.Equal(400, statusResult.StatusCode);
        }

        [Fact]
        public void Details_ValidId_ReturnsViewWithStudent()
        {
            var student = _context.Students.First();
            var result = _controller.Details(student.ID);

            var viewResult = Assert.IsType<ViewResult>(result);
            var model = Assert.IsType<Student>(viewResult.Model);
            Assert.Equal(student.ID, model.ID);
            // Should include enrollments
            Assert.NotNull(model.Enrollments);
        }

        // --- Create GET Tests ---

        [Fact]
        public void Create_GET_ReturnsViewWithDefaultDate()
        {
            var result = _controller.Create();

            var viewResult = Assert.IsType<ViewResult>(result);
            var model = Assert.IsType<Student>(viewResult.Model);
            Assert.Equal(DateTime.Today, model.EnrollmentDate);
        }

        // --- Create POST Tests ---

        [Fact]
        public void Create_POST_ValidStudent_RedirectsToIndex()
        {
            var student = new Student
            {
                LastName = "NewStudent",
                FirstMidName = "Test",
                EnrollmentDate = new DateTime(2023, 9, 1)
            };

            var result = _controller.Create(student);

            var redirectResult = Assert.IsType<RedirectToActionResult>(result);
            Assert.Equal("Index", redirectResult.ActionName);
        }

        [Fact]
        public void Create_POST_ValidStudent_SavesInDatabase()
        {
            var countBefore = _context.Students.Count();
            var student = new Student
            {
                LastName = "NewStudent",
                FirstMidName = "Test",
                EnrollmentDate = new DateTime(2023, 9, 1)
            };

            _controller.Create(student);

            Assert.Equal(countBefore + 1, _context.Students.Count());
            Assert.Contains(_context.Students, s => s.LastName == "NewStudent");
        }

        [Fact]
        public void Create_POST_InvalidModel_ReturnsView()
        {
            _controller.ModelState.AddModelError("LastName", "Required");
            var student = new Student();

            var result = _controller.Create(student);

            var viewResult = Assert.IsType<ViewResult>(result);
            Assert.IsType<Student>(viewResult.Model);
        }

        [Fact]
        public void Create_POST_MinValueDate_AddsModelError()
        {
            var student = new Student
            {
                LastName = "Test",
                FirstMidName = "User",
                EnrollmentDate = DateTime.MinValue
            };

            var result = _controller.Create(student);

            var viewResult = Assert.IsType<ViewResult>(result);
            Assert.False(_controller.ModelState.IsValid);
        }

        [Fact]
        public void Create_POST_DateTooEarly_AddsModelError()
        {
            var student = new Student
            {
                LastName = "Test",
                FirstMidName = "User",
                EnrollmentDate = new DateTime(1000, 1, 1)
            };

            var result = _controller.Create(student);

            var viewResult = Assert.IsType<ViewResult>(result);
            Assert.True(_controller.ModelState.ContainsKey("EnrollmentDate"));
        }

        // --- Edit GET Tests ---

        [Fact]
        public void Edit_GET_NullId_ReturnsBadRequest()
        {
            var result = _controller.Edit((int?)null);

            var statusResult = Assert.IsType<StatusCodeResult>(result);
            Assert.Equal(400, statusResult.StatusCode);
        }

        [Fact]
        public void Edit_GET_NotFound_ReturnsNotFound()
        {
            var result = _controller.Edit(99999);

            Assert.IsType<NotFoundResult>(result);
        }

        [Fact]
        public void Edit_GET_ValidId_ReturnsViewWithStudent()
        {
            var student = _context.Students.First();
            var result = _controller.Edit(student.ID);

            var viewResult = Assert.IsType<ViewResult>(result);
            var model = Assert.IsType<Student>(viewResult.Model);
            Assert.Equal(student.ID, model.ID);
        }

        // --- Edit POST Tests ---

        [Fact]
        public void Edit_POST_ValidStudent_RedirectsToIndex()
        {
            var student = _context.Students.AsNoTracking().First();
            student.LastName = "UpdatedName";

            var result = _controller.Edit(student);

            var redirectResult = Assert.IsType<RedirectToActionResult>(result);
            Assert.Equal("Index", redirectResult.ActionName);
        }

        [Fact]
        public void Edit_POST_ValidStudent_UpdatesDatabase()
        {
            var student = _context.Students.AsNoTracking().First();
            var studentId = student.ID;
            student.LastName = "UpdatedName";

            _controller.Edit(student);

            var updated = _context.Students.Find(studentId);
            Assert.Equal("UpdatedName", updated.LastName);
        }

        [Fact]
        public void Edit_POST_InvalidModel_ReturnsView()
        {
            _controller.ModelState.AddModelError("LastName", "Required");
            var student = new Student
            {
                ID = 1,
                EnrollmentDate = new DateTime(2023, 1, 1)
            };

            var result = _controller.Edit(student);

            Assert.IsType<ViewResult>(result);
        }

        [Fact]
        public void Edit_POST_MinValueDate_AddsModelError()
        {
            var student = _context.Students.AsNoTracking().First();
            student.EnrollmentDate = DateTime.MinValue;

            var result = _controller.Edit(student);

            Assert.IsType<ViewResult>(result);
            Assert.True(_controller.ModelState.ContainsKey("EnrollmentDate"));
        }

        // --- Delete GET Tests ---

        [Fact]
        public void Delete_GET_NullId_ReturnsBadRequest()
        {
            var result = _controller.Delete(null);

            var statusResult = Assert.IsType<StatusCodeResult>(result);
            Assert.Equal(400, statusResult.StatusCode);
        }

        [Fact]
        public void Delete_GET_NotFound_ReturnsNotFound()
        {
            var result = _controller.Delete(99999);

            Assert.IsType<NotFoundResult>(result);
        }

        [Fact]
        public void Delete_GET_ValidId_ReturnsView()
        {
            var student = _context.Students.First();
            var result = _controller.Delete(student.ID);

            var viewResult = Assert.IsType<ViewResult>(result);
            var model = Assert.IsType<Student>(viewResult.Model);
            Assert.Equal(student.ID, model.ID);
        }

        // --- DeleteConfirmed Tests ---

        [Fact]
        public void DeleteConfirmed_RemovesStudent_AndRedirects()
        {
            var student = _context.Students.First();
            var studentId = student.ID;
            var countBefore = _context.Students.Count();

            var result = _controller.DeleteConfirmed(studentId);

            Assert.IsType<RedirectToActionResult>(result);
            Assert.Equal(countBefore - 1, _context.Students.Count());
            Assert.Null(_context.Students.Find(studentId));
        }

        [Fact]
        public void DeleteConfirmed_InvalidId_RedirectsWithError()
        {
            // When student is not found, Find returns null, causing exception
            // which is caught and handled with TempData
            var result = _controller.DeleteConfirmed(99999);

            var redirectResult = Assert.IsType<RedirectToActionResult>(result);
            Assert.Equal("Index", redirectResult.ActionName);
        }
    }
}

using ContosoUniversity.Controllers;
