    public class NotificationsControllerTests : IDisposable
    {
        private readonly NotificationsController _controller;

        public NotificationsControllerTests()
        {
            TestHelpers.DrainNotificationQueue();
            var context = TestHelpers.CreateContext();
            _controller = new NotificationsController(context);
            TestHelpers.SetupController(_controller);
        }

        public void Dispose()
        {
            TestHelpers.DrainNotificationQueue();
            _controller.Dispose();
        }

        [Fact]
        public void GetNotifications_ReturnsJsonResult()
        {
            var result = _controller.GetNotifications();

            Assert.IsType<JsonResult>(result);
        }

        [Fact]
        public void GetNotifications_EmptyQueue_ReturnsSuccessWithZeroCount()
        {
            var result = _controller.GetNotifications();

            Assert.IsType<JsonResult>(result);
            // The value is an anonymous type, use dynamic or reflection
            var value = result.Value;
            Assert.NotNull(value);
        }

        [Fact]
        public void GetNotifications_WithNotifications_ReturnsNotifications()
        {
            // Enqueue some notifications
            var service = new NotificationService();
            service.SendNotification("Student", "1", "Test Student", EntityOperation.CREATE, "admin");
            service.SendNotification("Course", "101", "Chemistry", EntityOperation.UPDATE, "admin");

            var result = _controller.GetNotifications();

            Assert.IsType<JsonResult>(result);
            Assert.NotNull(result.Value);
        }

        [Fact]
        public void GetNotifications_LimitsTo10()
        {
            var service = new NotificationService();
            for (int i = 0; i < 15; i++)
            {
                service.SendNotification("Student", i.ToString(), EntityOperation.CREATE);
            }

            var result = _controller.GetNotifications();

            // After this call, 10 should be dequeued, 5 should remain
            Assert.NotNull(result.Value);

            // Verify only 5 remain in queue
            int remaining = 0;
            while (service.ReceiveNotification() != null) remaining++;
            Assert.Equal(5, remaining);
        }

        [Fact]
        public void MarkAsRead_ReturnsJsonResult()
        {
            var result = _controller.MarkAsRead(1);

            Assert.IsType<JsonResult>(result);
        }

        [Fact]
        public void MarkAsRead_ReturnsSuccess()
        {
            var result = _controller.MarkAsRead(42);

            Assert.IsType<JsonResult>(result);
            Assert.NotNull(result.Value);
        }

        [Fact]
        public void Index_ReturnsViewResult()
        {
            var result = _controller.Index();

            Assert.IsType<ViewResult>(result);
        }
    }
}

