using ContosoUniversity.Controllers;
using ContosoUniversity.Data;
using ContosoUniversity.Models;
using ContosoUniversity.Tests.Helpers;
using Microsoft.AspNetCore.Hosting;
using Microsoft.AspNetCore.Http;
using Microsoft.AspNetCore.Mvc;
using Microsoft.EntityFrameworkCore;
using Microsoft.Extensions.Logging;
using Moq;
using System;
using System.IO;
using System.Linq;
using Xunit;

namespace ContosoUniversity.Tests.Controllers
{
    public class CoursesControllerTests : IDisposable
    {
        private readonly SchoolContext _context;
        private readonly CoursesController _controller;
        private readonly Mock<IWebHostEnvironment> _mockEnv;
        private readonly Mock<ILogger<CoursesController>> _mockLogger;
        private readonly string _tempDir;

        public CoursesControllerTests()
        {
            TestHelpers.DrainNotificationQueue();
            _context = TestHelpers.CreateSeededContext();
            _mockEnv = new Mock<IWebHostEnvironment>();
            _mockLogger = new Mock<ILogger<CoursesController>>();

            _tempDir = Path.Combine(Path.GetTempPath(), Guid.NewGuid().ToString());
            Directory.CreateDirectory(_tempDir);
            _mockEnv.Setup(e => e.WebRootPath).Returns(_tempDir);
            _mockEnv.Setup(e => e.ContentRootPath).Returns(_tempDir);

            _controller = new CoursesController(_context, _mockEnv.Object, _mockLogger.Object);
            TestHelpers.SetupController(_controller);
        }

        public void Dispose()
        {
            TestHelpers.DrainNotificationQueue();
            _controller.Dispose();
            _context.Dispose();
            try { Directory.Delete(_tempDir, true); } catch { }
        }

        // --- Index Tests ---

        [Fact]
        public void Index_ReturnsViewWithCourses()
        {
            var result = _controller.Index();

            var viewResult = Assert.IsType<ViewResult>(result);
            var model = Assert.IsAssignableFrom<System.Collections.Generic.List<Course>>(viewResult.Model);
            Assert.Equal(3, model.Count);
        }

        // --- Details Tests ---

        [Fact]
        public void Details_NullId_ReturnsBadRequest()
        {
            var result = _controller.Details(null);

            var statusResult = Assert.IsType<StatusCodeResult>(result);
            Assert.Equal(400, statusResult.StatusCode);
        }

        [Fact]
        public void Details_ValidId_ReturnsCourse()
        {
            var result = _controller.Details(1001);

            var viewResult = Assert.IsType<ViewResult>(result);
            var model = Assert.IsType<Course>(viewResult.Model);
            Assert.Equal(1001, model.CourseID);
            Assert.Equal("Chemistry", model.Title);
        }

        // --- Create GET Tests ---

        [Fact]
        public void Create_GET_ReturnsViewWithDepartmentSelect()
        {
            var result = _controller.Create();

            var viewResult = Assert.IsType<ViewResult>(result);
            Assert.NotNull(_controller.ViewBag.DepartmentID);
            Assert.IsType<Course>(viewResult.Model);
        }

        // --- Create POST Tests ---

        [Fact]
        public void Create_POST_ValidCourse_RedirectsToIndex()
        {
            var dept = _context.Departments.First();
            var course = new Course
            {
                CourseID = 9001,
                Title = "New Course",
                Credits = 3,
                DepartmentID = dept.DepartmentID
            };

            var result = _controller.Create(course, null);

            var redirectResult = Assert.IsType<RedirectToActionResult>(result);
            Assert.Equal("Index", redirectResult.ActionName);
        }

        [Fact]
        public void Create_POST_ValidCourse_SavesInDatabase()
        {
            var dept = _context.Departments.First();
            var course = new Course
            {
                CourseID = 9002,
                Title = "Another Course",
                Credits = 4,
                DepartmentID = dept.DepartmentID
            };

            _controller.Create(course, null);

            Assert.NotNull(_context.Courses.Find(9002));
        }

        [Fact]
        public void Create_POST_InvalidModel_ReturnsView()
        {
            _controller.ModelState.AddModelError("Title", "Required");
            var course = new Course();

            var result = _controller.Create(course, null);

            Assert.IsType<ViewResult>(result);
            Assert.NotNull(_controller.ViewBag.DepartmentID);
        }

        [Fact]
        public void Create_POST_InvalidFileExtension_AddsModelError()
        {
            var dept = _context.Departments.First();
            var course = new Course
            {
                CourseID = 9003,
                Title = "Course With Bad File",
                Credits = 3,
                DepartmentID = dept.DepartmentID
            };
            var mockFile = CreateMockFile("test.exe", 1024);

            var result = _controller.Create(course, mockFile.Object);

            var viewResult = Assert.IsType<ViewResult>(result);
            Assert.True(_controller.ModelState.ContainsKey("teachingMaterialImage"));
        }

        [Fact]
        public void Create_POST_FileTooLarge_AddsModelError()
        {
            var dept = _context.Departments.First();
            var course = new Course
            {
                CourseID = 9004,
                Title = "Course With Big File",
                Credits = 3,
                DepartmentID = dept.DepartmentID
            };
            var mockFile = CreateMockFile("test.jpg", 6 * 1024 * 1024); // 6MB

            var result = _controller.Create(course, mockFile.Object);

            var viewResult = Assert.IsType<ViewResult>(result);
            Assert.True(_controller.ModelState.ContainsKey("teachingMaterialImage"));
        }

        [Fact]
        public void Create_POST_ValidImage_SetsImagePath()
        {
            var dept = _context.Departments.First();
            var course = new Course
            {
                CourseID = 9005,
                Title = "Course With Image",
                Credits = 3,
                DepartmentID = dept.DepartmentID
            };
            var mockFile = CreateMockFile("photo.jpg", 1024);

            _controller.Create(course, mockFile.Object);

            var saved = _context.Courses.Find(9005);
            Assert.NotNull(saved);
            Assert.StartsWith("/Uploads/TeachingMaterials/", saved.TeachingMaterialImagePath);
        }

        [Theory]
        [InlineData(".jpg")]
        [InlineData(".jpeg")]
        [InlineData(".png")]
        [InlineData(".gif")]
        [InlineData(".bmp")]
        public void Create_POST_AcceptsValidImageExtensions(string ext)
        {
            var dept = _context.Departments.First();
            var course = new Course
            {
                CourseID = 9006 + Math.Abs(ext.GetHashCode() % 1000),
                Title = $"Course{ext}",
                Credits = 3,
                DepartmentID = dept.DepartmentID
            };
            var mockFile = CreateMockFile($"photo{ext}", 1024);

            var result = _controller.Create(course, mockFile.Object);

            Assert.IsType<RedirectToActionResult>(result);
        }

        // --- Edit GET Tests ---

        [Fact]
        public void Edit_GET_NullId_ReturnsBadRequest()
        {
            var result = _controller.Edit((int?)null);

            var statusResult = Assert.IsType<StatusCodeResult>(result);
            Assert.Equal(400, statusResult.StatusCode);
        }

        [Fact]
        public void Edit_GET_NotFound_ReturnsNotFound()
        {
            var result = _controller.Edit(99999);

            Assert.IsType<NotFoundResult>(result);
        }

        [Fact]
        public void Edit_GET_ValidId_ReturnsViewWithCourse()
        {
            var result = _controller.Edit(1001);

            var viewResult = Assert.IsType<ViewResult>(result);
            var model = Assert.IsType<Course>(viewResult.Model);
            Assert.Equal(1001, model.CourseID);
            Assert.NotNull(_controller.ViewBag.DepartmentID);
        }

        // --- Edit POST Tests ---

        [Fact]
        public void Edit_POST_ValidCourse_RedirectsToIndex()
        {
            var course = _context.Courses.AsNoTracking().First(c => c.CourseID == 1001);
            course.Title = "Updated Chemistry";

            var result = _controller.Edit(course, null);

            var redirectResult = Assert.IsType<RedirectToActionResult>(result);
            Assert.Equal("Index", redirectResult.ActionName);
        }

        [Fact]
        public void Edit_POST_ValidCourse_UpdatesDatabase()
        {
            var course = _context.Courses.AsNoTracking().First(c => c.CourseID == 1001);
            course.Title = "Updated Chemistry";

            _controller.Edit(course, null);

            var updated = _context.Courses.Find(1001);
            Assert.Equal("Updated Chemistry", updated.Title);
        }

        [Fact]
        public void Edit_POST_InvalidModel_ReturnsView()
        {
            _controller.ModelState.AddModelError("Title", "Required");
            var course = new Course { CourseID = 1001, DepartmentID = 1 };

            var result = _controller.Edit(course, null);

            Assert.IsType<ViewResult>(result);
            Assert.NotNull(_controller.ViewBag.DepartmentID);
        }

        [Fact]
        public void Edit_POST_InvalidFileExtension_AddsError()
        {
            var course = _context.Courses.AsNoTracking().First(c => c.CourseID == 1001);
            var mockFile = CreateMockFile("test.txt", 1024);

            var result = _controller.Edit(course, mockFile.Object);

            Assert.IsType<ViewResult>(result);
            Assert.True(_controller.ModelState.ContainsKey("teachingMaterialImage"));
        }

        [Fact]
        public void Edit_POST_FileTooLarge_AddsError()
        {
            var course = _context.Courses.AsNoTracking().First(c => c.CourseID == 1001);
            var mockFile = CreateMockFile("test.png", 6 * 1024 * 1024);

            var result = _controller.Edit(course, mockFile.Object);

            Assert.IsType<ViewResult>(result);
            Assert.True(_controller.ModelState.ContainsKey("teachingMaterialImage"));
        }

        [Fact]
        public void Edit_POST_ValidImage_UpdatesImagePath()
        {
            var course = _context.Courses.AsNoTracking().First(c => c.CourseID == 1001);
            var mockFile = CreateMockFile("newphoto.png", 2048);

            _controller.Edit(course, mockFile.Object);

            var updated = _context.Courses.Find(1001);
            Assert.StartsWith("/Uploads/TeachingMaterials/", updated.TeachingMaterialImagePath);
        }

        // --- Delete GET Tests ---

        [Fact]
        public void Delete_GET_NullId_ReturnsBadRequest()
        {
            var result = _controller.Delete(null);

            var statusResult = Assert.IsType<StatusCodeResult>(result);
            Assert.Equal(400, statusResult.StatusCode);
        }

        [Fact]
        public void Delete_GET_ValidId_ReturnsView()
        {
            var result = _controller.Delete(1001);

            var viewResult = Assert.IsType<ViewResult>(result);
            var model = Assert.IsType<Course>(viewResult.Model);
            Assert.Equal(1001, model.CourseID);
        }

        // --- DeleteConfirmed Tests ---

        [Fact]
        public void DeleteConfirmed_RemovesCourse_AndRedirects()
        {
            var countBefore = _context.Courses.Count();

            var result = _controller.DeleteConfirmed(1001);

            Assert.IsType<RedirectToActionResult>(result);
            Assert.Equal(countBefore - 1, _context.Courses.Count());
            Assert.Null(_context.Courses.Find(1001));
        }

        [Fact]
        public void DeleteConfirmed_WithImage_DeletesFile()
        {
            // Set up a course with an image file
            var course = _context.Courses.Find(1001);
            var uploadsDir = Path.Combine(_tempDir, "Uploads", "TeachingMaterials");
            Directory.CreateDirectory(uploadsDir);
            var imagePath = Path.Combine(uploadsDir, "test_image.jpg");
            File.WriteAllBytes(imagePath, new byte[] { 0xFF, 0xD8 });
            course.TeachingMaterialImagePath = "/Uploads/TeachingMaterials/test_image.jpg";
            _context.SaveChanges();

            _controller.DeleteConfirmed(1001);

            Assert.False(File.Exists(imagePath));
        }

        // --- Helper ---

        private Mock<IFormFile> CreateMockFile(string fileName, long length)
        {
            var mock = new Mock<IFormFile>();
            mock.Setup(f => f.FileName).Returns(fileName);
            mock.Setup(f => f.Length).Returns(length);
            mock.Setup(f => f.CopyTo(It.IsAny<Stream>()));
            return mock;
        }
    }
}

