using ContosoUniversity.Controllers;
using ContosoUniversity.Data;
using ContosoUniversity.Models;
using ContosoUniversity.Tests.Helpers;
using Microsoft.AspNetCore.Mvc;
using Microsoft.EntityFrameworkCore;
using System;
using System.Linq;
using Xunit;

namespace ContosoUniversity.Tests.Controllers
{
    public class DepartmentsControllerTests : IDisposable
    {
        private readonly SchoolContext _context;
        private readonly DepartmentsController _controller;

        public DepartmentsControllerTests()
        {
            TestHelpers.DrainNotificationQueue();
            _context = TestHelpers.CreateSeededContext();
            _controller = new DepartmentsController(_context);
            TestHelpers.SetupController(_controller);
        }

        public void Dispose()
        {
            TestHelpers.DrainNotificationQueue();
            _controller.Dispose();
            _context.Dispose();
        }

        // --- Index Tests ---

        [Fact]
        public void Index_ReturnsViewWithDepartments()
        {
            var result = _controller.Index();

            var viewResult = Assert.IsType<ViewResult>(result);
            var model = Assert.IsAssignableFrom<System.Collections.Generic.List<Department>>(viewResult.Model);
            Assert.Equal(2, model.Count);
        }

        // --- Details Tests ---

        [Fact]
        public void Details_NullId_ReturnsBadRequest()
        {
            var result = _controller.Details(null);

            var statusResult = Assert.IsType<StatusCodeResult>(result);
            Assert.Equal(400, statusResult.StatusCode);
        }

        [Fact]
        public void Details_NotFound_ReturnsNotFound()
        {
            var result = _controller.Details(99999);

            Assert.IsType<NotFoundResult>(result);
        }

        [Fact]
        public void Details_ValidId_ReturnsViewWithDepartment()
        {
            var dept = _context.Departments.First();
            var result = _controller.Details(dept.DepartmentID);

            var viewResult = Assert.IsType<ViewResult>(result);
            var model = Assert.IsType<Department>(viewResult.Model);
            Assert.Equal(dept.DepartmentID, model.DepartmentID);
        }

        // --- Create GET Tests ---

        [Fact]
        public void Create_GET_ReturnsViewWithInstructorSelect()
        {
            var result = _controller.Create();

            Assert.IsType<ViewResult>(result);
            Assert.NotNull(_controller.ViewBag.InstructorID);
        }

        // --- Create POST Tests ---

        [Fact]
        public void Create_POST_ValidDepartment_RedirectsToIndex()
        {
            var instructor = _context.Instructors.First();
            var department = new Department
            {
                Name = "New Department",
                Budget = 200000m,
                StartDate = new DateTime(2023, 1, 1),
                InstructorID = instructor.ID
            };

            var result = _controller.Create(department);

            var redirectResult = Assert.IsType<RedirectToActionResult>(result);
            Assert.Equal("Index", redirectResult.ActionName);
        }

        [Fact]
        public void Create_POST_ValidDepartment_SavesInDatabase()
        {
            var countBefore = _context.Departments.Count();
            var instructor = _context.Instructors.First();
            var department = new Department
            {
                Name = "Science",
                Budget = 500000m,
                StartDate = new DateTime(2023, 9, 1),
                InstructorID = instructor.ID
            };

            _controller.Create(department);

            Assert.Equal(countBefore + 1, _context.Departments.Count());
            Assert.Contains(_context.Departments, d => d.Name == "Science");
        }

        [Fact]
        public void Create_POST_InvalidModel_ReturnsView()
        {
            _controller.ModelState.AddModelError("Name", "Required");
            var department = new Department();

            var result = _controller.Create(department);

            Assert.IsType<ViewResult>(result);
            Assert.NotNull(_controller.ViewBag.InstructorID);
        }

        // --- Edit GET Tests ---

        [Fact]
        public void Edit_GET_NullId_ReturnsBadRequest()
        {
            var result = _controller.Edit((int?)null);

            var statusResult = Assert.IsType<StatusCodeResult>(result);
            Assert.Equal(400, statusResult.StatusCode);
        }

        [Fact]
        public void Edit_GET_NotFound_ReturnsNotFound()
        {
            var result = _controller.Edit(99999);

            Assert.IsType<NotFoundResult>(result);
        }

        [Fact]
        public void Edit_GET_ValidId_ReturnsViewWithDepartment()
        {
            var dept = _context.Departments.First();
            var result = _controller.Edit(dept.DepartmentID);

            var viewResult = Assert.IsType<ViewResult>(result);
            var model = Assert.IsType<Department>(viewResult.Model);
            Assert.Equal(dept.DepartmentID, model.DepartmentID);
            Assert.NotNull(_controller.ViewBag.InstructorID);
        }

        // --- Edit POST Tests ---

        [Fact]
        public void Edit_POST_ValidDepartment_RedirectsToIndex()
        {
            var dept = _context.Departments.AsNoTracking().First();
            dept.Name = "Updated Name";

            var result = _controller.Edit(dept);

            var redirectResult = Assert.IsType<RedirectToActionResult>(result);
            Assert.Equal("Index", redirectResult.ActionName);
        }

        [Fact]
        public void Edit_POST_ValidDepartment_UpdatesDatabase()
        {
            var dept = _context.Departments.AsNoTracking().First();
            var deptId = dept.DepartmentID;
            dept.Name = "Updated Name";

            _controller.Edit(dept);

            var updated = _context.Departments.Find(deptId);
            Assert.Equal("Updated Name", updated.Name);
        }

        [Fact]
        public void Edit_POST_InvalidModel_ReturnsView()
        {
            _controller.ModelState.AddModelError("Name", "Required");
            var dept = new Department
            {
                DepartmentID = 1,
                StartDate = DateTime.Now
            };

            var result = _controller.Edit(dept);

            Assert.IsType<ViewResult>(result);
            Assert.NotNull(_controller.ViewBag.InstructorID);
        }

        // --- Delete GET Tests ---

        [Fact]
        public void Delete_GET_NullId_ReturnsBadRequest()
        {
            var result = _controller.Delete(null);

            var statusResult = Assert.IsType<StatusCodeResult>(result);
            Assert.Equal(400, statusResult.StatusCode);
        }

        [Fact]
        public void Delete_GET_NotFound_ReturnsNotFound()
        {
            var result = _controller.Delete(99999);

            Assert.IsType<NotFoundResult>(result);
        }

        [Fact]
        public void Delete_GET_ValidId_ReturnsView()
        {
            var dept = _context.Departments.First();
            var result = _controller.Delete(dept.DepartmentID);

            var viewResult = Assert.IsType<ViewResult>(result);
            Assert.IsType<Department>(viewResult.Model);
        }

        // --- DeleteConfirmed Tests ---

        [Fact]
        public void DeleteConfirmed_RemovesDepartment_AndRedirects()
        {
            var dept = _context.Departments.First();
            var deptId = dept.DepartmentID;
            var countBefore = _context.Departments.Count();

            var result = _controller.DeleteConfirmed(deptId);

            Assert.IsType<RedirectToActionResult>(result);
            Assert.Equal(countBefore - 1, _context.Departments.Count());
            Assert.Null(_context.Departments.Find(deptId));
        }
    }
}

