{
    public class InstructorsControllerTests : IDisposable
    {
        private readonly SchoolContext _context;
        private readonly InstructorsController _controller;

        public InstructorsControllerTests()
        {
            TestHelpers.DrainNotificationQueue();
            _context = TestHelpers.CreateSeededContext();
            _controller = new InstructorsController(_context);
            TestHelpers.SetupController(_controller);
        }

        public void Dispose()
        {
            TestHelpers.DrainNotificationQueue();
            _controller.Dispose();
            _context.Dispose();
        }

        // --- Index Tests ---

        [Fact]
        public void Index_NoSelection_ReturnsViewWithAllInstructors()
        {
            var result = _controller.Index(null, null);

            var viewResult = Assert.IsType<ViewResult>(result);
            var model = Assert.IsType<InstructorIndexData>(viewResult.Model);
            Assert.NotNull(model.Instructors);
            Assert.Equal(2, model.Instructors.Count());
        }

        [Fact]
        public void Index_WithInstructorId_PopulatesCourses()
        {
            var instructor = _context.Instructors.First();
            // Assign a course to this instructor
            var hasCourses = _context.CourseAssignments.Any(ca => ca.InstructorID == instructor.ID);

            var result = _controller.Index(instructor.ID, null);

            var viewResult = Assert.IsType<ViewResult>(result);
            var model = Assert.IsType<InstructorIndexData>(viewResult.Model);
            Assert.NotNull(model.Courses);
            Assert.Equal(instructor.ID, (int)_controller.ViewBag.InstructorID);
        }

        [Fact]
        public void Index_InstructorsOrderedByLastName()
        {
            var result = _controller.Index(null, null);

            var viewResult = Assert.IsType<ViewResult>(result);
            var model = Assert.IsType<InstructorIndexData>(viewResult.Model);
            var names = model.Instructors.Select(i => i.LastName).ToList();
            Assert.Equal(names.OrderBy(n => n).ToList(), names);
        }

        // --- Details Tests ---

        [Fact]
        public void Details_NullId_ReturnsBadRequest()
        {
            var result = _controller.Details(null);

            var statusResult = Assert.IsType<StatusCodeResult>(result);
            Assert.Equal(400, statusResult.StatusCode);
        }

        [Fact]
        public void Details_NotFound_ReturnsNotFound()
        {
            var result = _controller.Details(99999);

            Assert.IsType<NotFoundResult>(result);
        }

        [Fact]
        public void Details_ValidId_ReturnsViewWithInstructor()
        {
            var instructor = _context.Instructors.First();
            var result = _controller.Details(instructor.ID);

            var viewResult = Assert.IsType<ViewResult>(result);
            var model = Assert.IsType<Instructor>(viewResult.Model);
            Assert.Equal(instructor.ID, model.ID);
        }

        // --- Create GET Tests ---

        [Fact]
        public void Create_GET_ReturnsViewWithCourseData()
        {
            var result = _controller.Create();

            var viewResult = Assert.IsType<ViewResult>(result);
            var model = Assert.IsType<Instructor>(viewResult.Model);
            Assert.NotNull(model.CourseAssignments);
            Assert.Empty(model.CourseAssignments);
            Assert.NotNull(_controller.ViewBag.Courses);
        }

        [Fact]
        public void Create_GET_PopulatesAssignedCourseData()
        {
            _controller.Create();

            var courses = _controller.ViewBag.Courses as List<AssignedCourseData>;
            Assert.NotNull(courses);
            Assert.Equal(_context.Courses.Count(), courses.Count);
            Assert.All(courses, c => Assert.False(c.Assigned)); // None assigned for new instructor
        }

        // --- Create POST Tests ---

        [Fact]
        public void Create_POST_ValidInstructor_RedirectsToIndex()
        {
            var instructor = new Instructor
            {
                LastName = "NewInstructor",
                FirstMidName = "Test",
                HireDate = new DateTime(2023, 1, 1)
            };

            var result = _controller.Create(instructor, null);

            var redirectResult = Assert.IsType<RedirectToActionResult>(result);
            Assert.Equal("Index", redirectResult.ActionName);
        }

        [Fact]
        public void Create_POST_ValidInstructor_SavesInDatabase()
        {
            var countBefore = _context.Instructors.Count();
            var instructor = new Instructor
            {
                LastName = "NewInstructor",
                FirstMidName = "Test",
                HireDate = new DateTime(2023, 1, 1)
            };

            _controller.Create(instructor, null);

            Assert.Equal(countBefore + 1, _context.Instructors.Count());
        }

        [Fact]
        public void Create_POST_WithSelectedCourses_CreatesCourseAssignments()
        {
            var instructor = new Instructor
            {
                LastName = "WithCourses",
                FirstMidName = "Instructor",
                HireDate = new DateTime(2023, 1, 1)
            };
            var selectedCourses = new[] { "1001", "1002" };

            _controller.Create(instructor, selectedCourses);

            var saved = _context.Instructors.Include(i => i.CourseAssignments)
                .Single(i => i.LastName == "WithCourses");
            Assert.Equal(2, saved.CourseAssignments.Count);
        }

        [Fact]
        public void Create_POST_NullSelectedCourses_NoAssignments()
        {
            var instructor = new Instructor
            {
                LastName = "NoCourses",
                FirstMidName = "Instructor",
                HireDate = new DateTime(2023, 1, 1)
            };

            _controller.Create(instructor, null);

            var saved = _context.Instructors.Include(i => i.CourseAssignments)
                .Single(i => i.LastName == "NoCourses");
            Assert.Empty(saved.CourseAssignments);
        }

        [Fact]
        public void Create_POST_InvalidModel_ReturnsView()
        {
            _controller.ModelState.AddModelError("LastName", "Required");
            var instructor = new Instructor
            {
                HireDate = new DateTime(2023, 1, 1),
                CourseAssignments = new List<CourseAssignment>()
            };

            var result = _controller.Create(instructor, null);

            Assert.IsType<ViewResult>(result);
            Assert.NotNull(_controller.ViewBag.Courses);
        }

        // --- Edit GET Tests ---

        [Fact]
        public void Edit_GET_NullId_ReturnsBadRequest()
        {
            var result = _controller.Edit((int?)null);

            var statusResult = Assert.IsType<StatusCodeResult>(result);
            Assert.Equal(400, statusResult.StatusCode);
        }

        [Fact]
        public void Edit_GET_ValidId_ReturnsViewWithInstructorAndCourseData()
        {
            var instructor = _context.Instructors.First();
            var result = _controller.Edit(instructor.ID);

            var viewResult = Assert.IsType<ViewResult>(result);
            Assert.IsType<Instructor>(viewResult.Model);
            Assert.NotNull(_controller.ViewBag.Courses);
        }

        // --- Delete GET Tests ---

        [Fact]
        public void Delete_GET_NullId_ReturnsBadRequest()
        {
            var result = _controller.Delete(null);

            var statusResult = Assert.IsType<StatusCodeResult>(result);
            Assert.Equal(400, statusResult.StatusCode);
        }

        [Fact]
        public void Delete_GET_NotFound_ReturnsNotFound()
        {
            var result = _controller.Delete(99999);

            Assert.IsType<NotFoundResult>(result);
        }

        [Fact]
        public void Delete_GET_ValidId_ReturnsView()
        {
            var instructor = _context.Instructors.First();
            var result = _controller.Delete(instructor.ID);

            var viewResult = Assert.IsType<ViewResult>(result);
            Assert.IsType<Instructor>(viewResult.Model);
        }

        // --- DeleteConfirmed Tests ---

        [Fact]
        public void DeleteConfirmed_RemovesInstructor_AndRedirects()
        {
            // Use second instructor (not assigned as department admin)
            var instructor = _context.Instructors.OrderBy(i => i.ID).Last();
            var instructorId = instructor.ID;
            var countBefore = _context.Instructors.Count();

            var result = _controller.DeleteConfirmed(instructorId);

            Assert.IsType<RedirectToActionResult>(result);
            Assert.Equal(countBefore - 1, _context.Instructors.Count());
        }

        [Fact]
        public void DeleteConfirmed_ClearsDepartmentAdministrator()
        {
            // Instructor1 is department administrator
            var instructor = _context.Instructors.First();
            var dept = _context.Departments.First(d => d.InstructorID == instructor.ID);

            _controller.DeleteConfirmed(instructor.ID);

            _context.Entry(dept).Reload();
            Assert.Null(dept.InstructorID);
        }

        [Fact]
        public void DeleteConfirmed_RemovesOfficeAssignment()
        {
            var instructor = _context.Instructors.Include(i => i.OfficeAssignment)
                .First(i => i.OfficeAssignment != null);
            var instructorId = instructor.ID;

            _controller.DeleteConfirmed(instructorId);

            Assert.Null(_context.OfficeAssignments.Find(instructorId));
        }
    }
}

